## Deliverables

### 1. Single Resource Response Envelope
```typescript
// packages/shared/src/api/envelope.ts

/**
 * Envelope for single resource responses.
 * @template T The resource type
 */
export interface ApiResponse<T> {
  /** The resource type identifier (e.g., "agent", "checkpoint") */
  object: string;
  /** The resource data */
  data: T;
  /** Unique request identifier for debugging */
  requestId: string;
  /** ISO 8601 timestamp of response */
  timestamp: string;
  /** Optional HATEOAS links */
  links?: Record<string, string>;
}
```

### 2. List Response Envelope
```typescript
/**
 * Envelope for list/collection responses.
 * @template T The item type
 */
export interface ApiListResponse<T> {
  /** Always "list" for collections */
  object: "list";
  /** Array of items */
  data: T[];
  /** Pagination cursor for next page (if hasMore is true) */
  nextCursor?: string;
  /** Whether more items exist */
  hasMore: boolean;
  /** Total count (if available) */
  total?: number;
  /** URL for this list endpoint */
  url: string;
  /** Unique request identifier */
  requestId: string;
  /** ISO 8601 timestamp */
  timestamp: string;
}
```

### 3. Error Response Envelope
```typescript
/**
 * Envelope for error responses.
 */
export interface ApiErrorResponse {
  /** Always "error" */
  object: "error";
  /** Error details */
  error: {
    /** Error code from taxonomy */
    code: string;
    /** Human-readable message */
    message: string;
    /** Error severity for AI agents */
    severity?: "terminal" | "recoverable" | "retry";
    /** Suggested action to resolve */
    hint?: string;
