  sessionId: string;
}

export function SweepDCGSummary({ sessionId }: SweepDCGSummaryProps) {
  const { data: summary } = useSweepDCGSummary(sessionId);

  if (!summary) return null;

  const hasIssues = summary.blocks > 0 || summary.pending > 0;

  return (
    <Card className={hasIssues ? "border-yellow-500" : "border-green-500"}>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Shield className="h-5 w-5" />
          DCG Safety Status
        </CardTitle>
      </CardHeader>
      <CardContent>
        {hasIssues ? (
          <Alert variant="warning">
            <AlertTriangle className="h-4 w-4" />
            <AlertDescription>
              Some commands in this sweep triggered DCG warnings. Review before proceeding.
            </AlertDescription>
          </Alert>
        ) : (
          <Alert variant="success">
            <CheckCircle className="h-4 w-4" />
            <AlertDescription>
              All commands passed DCG validation.
            </AlertDescription>
          </Alert>
        )}

        <div className="grid grid-cols-4 gap-4 mt-4">
          <div className="text-center">
            <p className="text-2xl font-bold text-red-500">{summary.blocks}</p>
            <p className="text-xs text-muted-foreground">Blocked</p>
          </div>
          <div className="text-center">
            <p className="text-2xl font-bold text-yellow-500">{summary.pending}</p>
            <p className="text-xs text-muted-foreground">Pending</p>
          </div>
          <div className="text-center">
            <p className="text-2xl font-bold text-green-500">{summary.approved}</p>
            <p className="text-xs text-muted-foreground">Approved</p>
          </div>
          <div className="text-center">
            <p className="text-2xl font-bold text-gray-500">{summary.denied}</p>
            <p className="text-xs text-muted-foreground">Denied</p>
          </div>
        </div>

        {summary.blockDetails.length > 0 && (
          <div className="mt-4 space-y-2">
            <h4 className="font-semibold">Blocked Commands:</h4>
            {summary.blockDetails.map((block) => (
              <div key={block.id} className="bg-red-50 p-2 rounded text-sm">
                <code className="block truncate">{block.command}</code>
                <span className="text-red-600">{block.reason}</span>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}
```

