+export interface Finding {
+  id: string;
+  type: FindingType;
+  severity: FindingSeverity;
+  file: string;
+  line: number;
+  column: number;
+  message: string;
+  suggestion?: string;
+  category: string;
+  confidence: number;
+  status: FindingStatus;
+  ruleId?: string;
+  dismissedBy?: string;
+  dismissedAt?: Date;
+  dismissReason?: string;
+}
+
+export interface ScanOptions {
+  /** Files or directories to scan */
+  paths?: string[];
+  /** Only scan staged files */
+  staged?: boolean;
+  /** Only scan changed files (working tree vs HEAD) */
+  diff?: boolean;
+  /** Language filter (e.g., ["js", "python"]) */
+  languages?: string[];
+  /** Category filter */
+  categories?: number[];
+  /** Categories to skip */
+  skipCategories?: number[];
+  /** Profile: "strict" or "loose" */
+  profile?: "strict" | "loose";
+  /** Fail on warnings (for CI mode) */
+  failOnWarning?: boolean;
+  /** Paths to exclude */
+  exclude?: string[];
+  /** Custom rules directory */
+  rulesDir?: string;
+}
+
+export interface ScanResult {
+  scanId: string;
+  status: "success" | "failed" | "error";
+  exitCode: number;
+  startedAt: Date;
+  completedAt: Date;
+  durationMs: number;
+  filesScanned: number;
+  findings: Finding[];
+  summary: {
+    total: number;
+    critical: number;
+    high: number;
+    medium: number;
+    low: number;
+    byCategory: Record<string, number>;
+  };
+  error?: string;
+}
+
+export interface FindingFilter {
+  severity?: FindingSeverity;
+  type?: FindingType;
+  status?: FindingStatus;
+  file?: string;
+  category?: string;
+  limit?: number;
+  offset?: number;
+}
+
+export interface ScanHistoryEntry {
+  scanId: string;
+  startedAt: Date;
+  completedAt: Date;
+  durationMs: number;
+  exitCode: number;
+  filesScanned: number;
+  totalFindings: number;
+  criticalFindings: number;
+  paths: string[];
+}
+
+// ============================================================================
+// Internal Storage (in-memory for now, could be persisted to SQLite)
+// ============================================================================
+
+interface ScanStore {
+  scans: Map<string, ScanResult>;
